  "steps": [
    {
      "order": 1,
      "title": "돼지고기 손질하기",
      "description": [
        {
          "content": "키친타월로 돼지고기(앞다리살)의 핏물을 꼼꼼하게 닦아주세요.",
          "start": "00:00:15",
          "end": "00:00:30"
        },
        {
          "content": "핏물을 제거한 고기를 먹기 좋은 크기로 썰어주세요.",
          "start": "00:00:33",
          "end": "00:00:41"
        }
      ],
      "timerSeconds": null,
      "scenes": [
        {
          "start": "00:00:35",
          "end": "00:00:40",
          "label": "먹기 좋은 크기"
        }
      ]
    },
    {
      "order": 2,
      "title": "양념장 만들기",
      "description": [
        {
          "content": "보관 용기에 설탕 2T를 넣어주세요.",
          "start": "00:01:21",
          "end": "00:01:29"
        },
        {
          "content": "간장 3T를 넣어주세요.",
          "start": "00:01:34",
          "end": "00:01:40"
        },
        {
          "content": "고추장을 크게 3T 넣어주세요.",
          "start": "00:01:41",
          "end": "00:01:56"
        },
        {
          "content": "배 음료를 넣어 양념의 농도와 단맛을 조절해주세요.",
          "start": "00:02:16",
          "end": "00:02:25"
        }
      ],
      "timerSeconds": null,
      "scenes": [
        {
          "start": "00:01:45",
          "end": "00:01:53",
          "label": "고추장 크게 3T"
        },
        {
          "start": "00:02:18",
          "end": "00:02:25",
          "label": "양념의 농도 조절"
        }
      ]
    },
    {
      "order": 3,
      "title": "양념장 완성하기",
      "description": [
        {
          "content": "용기 뚜껑을 닫고 잘 흔들어 양념을 섞어주세요.",
          "start": "00:02:26",
          "end": "00:02:33"
        },
        {
          "content": "다진 마늘 1T를 넣어 섞어주세요.",
          "start": "00:02:38",
          "end": "00:02:46"
        }
      ],
      "timerSeconds": null,
      "scenes": []
    },
    {
      "order": 4,
      "title": "돼지고기 재우기",
      "description": [
        {
          "content": "완성된 양념장에 손질한 고기를 넣어주세요.",
          "start": "00:03:22",
          "end": "00:03:28"
        },
        {
          "content": "고기가 뭉치지 않도록 양념이 잘 배게 펴면서 섞어주세요.",
          "start": "00:03:28",
          "end": "00:03:35"
        },
        {
          "content": "식초 2T를 넣어 잡내를 잡고 보존성을 높여주세요.",
          "start": "00:03:49",
          "end": "00:04:00"
        },
        {
          "content": "참기름 1T를 추가해주세요.",
          "start": "00:04:36",
          "end": "00:04:46"
        }
      ],
      "timerSeconds": null,
      "scenes": [
        {
          "start": "00:03:28",
          "end": "00:03:35",
          "label": "뭉치지 않게 섞기"
        }
      ]
    },
    {
      "order": 5,
      "title": "야채 손질하여 올리기",
      "description": [
        {
          "content": "대파를 어슷하게 썰어 준비해주세요.",
          "start": "00:05:15",
          "end": "00:05:22"
        },
        {
          "content": "재워둔 고기 위에 썰어둔 대파와 양파를 섞지 않고 그대로 올려주세요.",
          "start": "00:05:22",
          "end": "00:05:27"
        },
        {
          "content": "야채 위에 소금 한 꼬집을 뿌려 야채의 아삭함을 살려주세요.",
          "start": "00:05:28",
          "end": "00:05:38"
        }
      ],
      "timerSeconds": null,
      "scenes": [
        {
          "start": "00:05:16",
          "end": "00:05:21",
          "label": "대파 어슷하게 썰기"
        },
        {
          "start": "00:05:30",
          "end": "00:05:35",
          "label": "소금 한 꼬집"
        }
      ]
    },
    {
      "order": 6,
      "title": "고기 먼저 볶기",
      "description": [
        {
          "content": "조리 시 야채는 걷어내고 고기만 먼저 팬에 올려주세요.",
          "start": "00:06:15",
          "end": "00:06:32"
        },
        {
          "content": "고기를 팬에 펼쳐놓고 뒤적이지 않은 채 거뭇하게 익을 때까지 기다려주세요.",
          "start": "00:06:40",
          "end": "00:07:05"
        },
        {
          "content": "고기 표면이 노릇해지면 골고루 섞으며 볶아주세요.",
          "start": "00:07:21",
          "end": "00:07:28"
        }
      ],
      "timerSeconds": null,
      "scenes": [
        {
          "start": "00:06:20",
          "end": "00:06:30",
          "label": "고기만 먼저 올리기"
        },
        {
          "start": "00:06:45",
          "end": "00:07:00",
          "label": "뒤적이지 않은 채"
        },
        {
          "start": "00:07:21",
          "end": "00:07:26",
          "label": "표면이 노릇해지면"
        }
      ]
    },
    {
      "order": 7,
      "title": "야채 넣고 익히기",
      "description": [
        {
          "content": "남겨두었던 야채와 남은 국물을 모두 팬에 넣어주세요.",
          "start": "00:07:28",
          "end": "00:07:47"
        },
        {
          "content": "팬의 뚜껑을 덮어주세요.",
          "start": "00:07:50",
          "end": "00:07:57"
        },
        {
          "content": "약불로 조절하여 3분간 더 익혀주세요.",
          "start": "00:08:03",
          "end": "00:08:08"
        },
        {
          "content": "뚜껑을 열고 상태를 확인해주세요.",
          "start": "00:08:23",
          "end": "00:08:26"
        }
      ],
      "timerSeconds": 180,
      "scenes": [
        {
          "start": "00:08:03",
          "end": "00:08:07",
          "label": "약불로 조절"
        },
        {
          "start": "00:08:23",
          "end": "00:08:26",
          "label": "상태 확인하기"
        }
      ]
    },
    {
      "order": 8,
      "title": "마무리하기",
      "description": [
        {
          "content": "풍미를 더하기 위해 다진 마늘 1T를 마지막으로 넣어주세요.",
          "start": "00:08:50",
          "end": "00:08:59"
        },
        {
          "content": "후추를 살짝 뿌려주세요.",
          "start": "00:09:03",
          "end": "00:09:08"
        },
        {
          "content": "모든 재료를 한 번 더 섞어 완성하세요.",
          "start": "00:09:08",
          "end": "00:09:14"
        }
      ],
      "timerSeconds": null,
      "scenes": []
    }
  ],
  "servingTip": null
}
